// frontend/src/components/ERPChatBot/ERPChatBot.jsx
import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './ERPChatBot.css';

const ERPChatBot = ({ studentId, studentName }) => {
    const [messages, setMessages] = useState([]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [suggestions, setSuggestions] = useState([]);
    const messagesEndRef = useRef(null);

    // Initialize chatbot
    useEffect(() => {
        loadSuggestions();
        setMessages([{
            id: 1,
            text: `Hi ${studentName}! I'm your ERP AI assistant. I can help you with:\n• Courses & Teachers\n• Fees & Payments\n• Attendance\n• Grades & GPA\n• Timetable\n• Assignments\n• Academic Progress\n\nAsk me anything!`,
            sender: 'bot',
            timestamp: new Date().toLocaleTimeString()
        }]);
    }, [studentName]);

    const loadSuggestions = async () => {
        try {
            const response = await axios.get('/api/chatbot/suggestions', {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            });
            setSuggestions(response.data.suggestions || []);
        } catch (error) {
            console.error("Failed to load suggestions:", error);
        }
    };

    const handleSend = async () => {
        if (!input.trim()) return;

        const userMessage = {
            id: Date.now(),
            text: input,
            sender: 'user',
            timestamp: new Date().toLocaleTimeString()
        };
        
        setMessages(prev => [...prev, userMessage]);
        setInput('');
        setIsLoading(true);

        try {
            const response = await axios.post('/api/chatbot/ask', {
                question: input
            }, {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            });

            const botMessage = {
                id: Date.now() + 1,
                text: response.data.answer,
                sender: 'bot',
                timestamp: new Date().toLocaleTimeString(),
                data: response.data
            };
            
            setMessages(prev => [...prev, botMessage]);

        } catch (error) {
            const errorMessage = {
                id: Date.now() + 1,
                text: "Sorry, I'm having trouble connecting. Please try again or contact support.",
                sender: 'bot',
                timestamp: new Date().toLocaleTimeString(),
                isError: true
            };
            
            setMessages(prev => [...prev, errorMessage]);
        } finally {
            setIsLoading(false);
            scrollToBottom();
        }
    };

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    const handleQuickQuestion = (question) => {
        setInput(question);
    };

    return (
        <div className="erp-chatbot">
            {/* Header */}
            <div className="chatbot-header">
                <div className="header-left">
                    <div className="ai-indicator">
                        <span className="pulse"></span>
                        AI Assistant
                    </div>
                    <div className="student-badge">
                        {studentName} • {studentId}
                    </div>
                </div>
                <div className="header-right">
                    <button className="clear-btn" onClick={() => setMessages([])}>
                        Clear Chat
                    </button>
                </div>
            </div>

            {/* Messages */}
            <div className="messages-container">
                {messages.map(msg => (
                    <div key={msg.id} className={`message-row ${msg.sender}`}>
                        <div className="message-avatar">
                            {msg.sender === 'bot' ? '🤖' : '👤'}
                        </div>
                        <div className="message-content">
                            <div className="message-text">{msg.text}</div>
                            <div className="message-time">{msg.timestamp}</div>
                        </div>
                    </div>
                ))}
                
                {isLoading && (
                    <div className="message-row bot">
                        <div className="message-avatar">🤖</div>
                        <div className="message-content">
                            <div className="typing-indicator">
                                <span></span>
                                <span></span>
                                <span></span>
                            </div>
                        </div>
                    </div>
                )}
                
                <div ref={messagesEndRef} />
            </div>

            {/* Quick Suggestions */}
            {suggestions.length > 0 && (
                <div className="quick-suggestions">
                    <div className="suggestions-title">Quick Questions:</div>
                    <div className="suggestions-grid">
                        {suggestions.map((suggestion, index) => (
                            <button
                                key={index}
                                className="suggestion-btn"
                                onClick={() => handleQuickQuestion(suggestion)}
                            >
                                {suggestion}
                            </button>
                        ))}
                    </div>
                </div>
            )}

            {/* Input Area */}
            <div className="input-container">
                <input
                    type="text"
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && !e.shiftKey && handleSend()}
                    placeholder="Ask me anything about your academics..."
                    className="chat-input"
                    disabled={isLoading}
                />
                <button
                    onClick={handleSend}
                    disabled={!input.trim() || isLoading}
                    className="send-btn"
                >
                    {isLoading ? '...' : 'Send'}
                </button>
            </div>
        </div>
    );
};

export default ERPChatBot;
